      { id: 'C', text: 'Use Amazon DynamoDB global tables for the product catalog and regional tables for the customer purchase data.' },
      { id: 'D', text: 'Use Aurora with read replicas for the product catalog and additional local Aurora instances in each region for the customer purchase data.' }
